function renderCompare(){
  document.getElementById('compare').innerHTML=
    '<div class="card" style="border-left:4px solid var(--accent)">'+
    '<h2>⚖️ Melbourne vs Sydney — Full Comparison</h2>'+
    '<p class="ts tm">Side-by-side for a family of 4 relocating from the UK</p>'+
    '<div class="stabs mt2">'+
    '<div class="stab active" onclick="showCmp(\'costs\',this)">💰 Costs</div>'+
    '<div class="stab" onclick="showCmp(\'housing\',this)">🏠 Housing</div>'+
    '<div class="stab" onclick="showCmp(\'schools\',this)">🏫 Schools</div>'+
    '<div class="stab" onclick="showCmp(\'lifestyle\',this)">🌏 Lifestyle</div>'+
    '<div class="stab" onclick="showCmp(\'verdict\',this)">🎯 Verdict</div>'+
    '</div></div><div id="cmpContent"></div>';
  showCmp('costs');
}
function showCmp(id,btn){
  if(btn){document.querySelectorAll('#compare .stab').forEach(function(s){s.classList.remove('active')});btn.classList.add('active')}
  document.getElementById('cmpContent').innerHTML=CMP[id]||'';
}
var CMP={};
CMP.costs='<div class="card"><h2>💰 Monthly Living Costs — Family of 4</h2><p class="tx tm mb2">2025-2026 data. Family renting 3-bed in good school catchment.</p><div class="table-wrap"><table><tr><th>Expense</th><th style="color:var(--accent)">🏙️ Melbourne</th><th style="color:var(--orange)">🌊 Sydney</th><th>Diff</th></tr><tr><td style="font-weight:600">Rent (3-bed, good area)</td><td>$2,800–$3,500/mo</td><td>$3,600–$4,800/mo</td><td class="tr">Syd +35%</td></tr><tr><td style="font-weight:600">Groceries</td><td>$1,200–$1,500</td><td>$1,400–$1,700</td><td class="tr">Syd +15%</td></tr><tr><td style="font-weight:600">Transport</td><td>$400–$600</td><td>$500–$700</td><td class="tr">Syd +15%</td></tr><tr><td style="font-weight:600">Utilities + Internet</td><td>$350–$450</td><td>$300–$400</td><td style="color:var(--green)">Melb +10%</td></tr><tr><td style="font-weight:600">Health Insurance (OVHC)</td><td>$300–$500</td><td>$300–$500</td><td>Same</td></tr><tr><td style="font-weight:600">Mobiles (family)</td><td>$120–$150</td><td>$120–$150</td><td>Same</td></tr><tr><td style="font-weight:600">Kids activities</td><td>$200–$400</td><td>$200–$400</td><td>Same</td></tr><tr><td style="font-weight:600">Eating out (2x/mo)</td><td>$200–$300</td><td>$250–$350</td><td class="tr">Syd +15%</td></tr><tr><td style="font-weight:600">UK flights (family of 4, amortised)</td><td>$417/mo<br><span class="tx tm">~$5,000/yr</span></td><td>$383/mo<br><span class="tx tm">~$4,600/yr</span></td><td>Similar</td></tr><tr style="font-weight:700;font-size:1rem"><td>TOTAL MONTHLY (inc flights)</td><td style="color:var(--accent)">$5,990–$7,820</td><td style="color:var(--orange)">$7,050–$9,380</td><td class="tr">Syd +$1,060–$1,560</td></tr><tr style="font-weight:700"><td>ANNUAL DIFFERENCE</td><td colspan="2"></td><td class="tr">Syd +$13k–$19k/yr</td></tr></table></div></div><div class="card"><h2>📊 Your Net Position</h2><p class="tx tm mb2">Based on ~$10,400/mo net salary</p><div class="table-wrap"><table><tr><th></th><th style="color:var(--accent)">Melbourne</th><th style="color:var(--orange)">Sydney</th></tr><tr><td>Income (net)</td><td>$10,400</td><td>$10,400</td></tr><tr><td>AU living costs</td><td style="color:var(--orange)">-$6,500</td><td style="color:var(--red)">-$7,800</td></tr><tr><td>UK costs (net of rent)</td><td>-$300</td><td>-$300</td></tr><tr style="font-weight:700;font-size:1rem"><td>Monthly surplus</td><td style="color:var(--green)">~$3,600</td><td style="color:var(--orange)">~$2,300</td></tr><tr style="font-weight:700"><td>Annual surplus</td><td style="color:var(--green)">~$43,200</td><td style="color:var(--orange)">~$27,600</td></tr></table></div><p class="ts mt2" style="color:var(--green);font-weight:600">Melbourne = ~$15,600/yr more surplus</p></div>';
CMP.housing='<div class="card"><h2>🏠 Housing</h2><div class="table-wrap"><table><tr><th></th><th style="color:var(--accent)">Melbourne</th><th style="color:var(--orange)">Sydney</th></tr><tr><td style="font-weight:600">Family rent (3-bed)</td><td>$700–$875/wk</td><td>$900–$1,200/wk</td></tr><tr><td style="font-weight:600">Median house price</td><td>~$1.11M</td><td>~$1.63M (+47%)</td></tr><tr><td style="font-weight:600">Bond</td><td>4 weeks rent</td><td>4 weeks rent</td></tr><tr><td style="font-weight:600">Market</td><td>Competitive</td><td>Very competitive</td></tr></table></div></div><div class="card"><h2>🏠 Target Suburbs</h2><div class="table-wrap"><table><tr><th style="color:var(--accent)">Melbourne</th><th>$/wk</th><th>Why</th></tr><tr><td>Glen Waverley</td><td>$650–$850</td><td>Top schools, family-friendly</td></tr><tr><td>Mount Waverley</td><td>$600–$800</td><td>Quieter, good primaries</td></tr><tr><td>Box Hill</td><td>$550–$750</td><td>Great transport, affordable</td></tr><tr><td>Doncaster</td><td>$650–$850</td><td>Safe, family area</td></tr><tr><td>Burwood</td><td>$600–$800</td><td>Central, good access</td></tr></table></div><div class="table-wrap"><table><tr><th style="color:var(--orange)">Sydney</th><th>$/wk</th><th>Why</th></tr><tr><td>Epping</td><td>$750–$950</td><td>Good schools, metro</td></tr><tr><td>Carlingford</td><td>$750–$950</td><td>Family area, near selective schools</td></tr><tr><td>Baulkham Hills</td><td>$800–$1,000</td><td>Top selective zone, safe</td></tr><tr><td>Hurstville</td><td>$700–$900</td><td>South, good transport</td></tr><tr><td>Chatswood</td><td>$900–$1,200</td><td>North Shore, pricey</td></tr></table></div></div>';
CMP.schools='<div class="card"><h2>🏫 Schools</h2><div class="table-wrap"><table><tr><th></th><th style="color:var(--accent)">Melbourne (VIC)</th><th style="color:var(--orange)">Sydney (NSW)</th></tr><tr><td style="font-weight:600">Exam system</td><td>VCE → ATAR</td><td>HSC → ATAR</td></tr><tr><td style="font-weight:600">Best govt zoned school</td><td>Balwyn HS (91.50)<br>Glen Waverley SC (91.40)</td><td>Cherrybrook Tech (88.93)</td></tr><tr><td style="font-weight:600">Selective schools</td><td>5 schools, from Year 9</td><td>Larger network, from Year 7</td></tr><tr><td style="font-weight:600">Top selective</td><td>MacRobertson Girls (99.30)</td><td>James Ruse (97.75)</td></tr><tr><td style="font-weight:600">Temp resident fees</td><td>$5k–$12k/yr per child</td><td>$5k–$12k/yr per child</td></tr></table></div></div><div class="card"><h2>🏫 For Your 14-Year-Old</h2><div class="table-wrap"><table><tr><th style="color:var(--accent)">Melbourne</th><th>Score</th></tr><tr><td>Glen Waverley SC</td><td>91.40</td></tr><tr><td>Balwyn HS</td><td>91.50</td></tr><tr><td>Mt Waverley SC</td><td>—</td></tr></table></div><div class="table-wrap"><table><tr><th style="color:var(--orange)">Sydney</th><th>Score</th></tr><tr><td>Cherrybrook Tech</td><td>88.93</td></tr><tr><td>Epping Boys HS</td><td>—</td></tr><tr><td>Carlingford HS</td><td>—</td></tr></table></div><p class="ts mt2" style="font-weight:600;color:var(--accent)">Melbourne wins on zoned govt schools — 91+ vs 89.</p><p class="ts">Catchments: <a href="https://www.findmyschool.vic.gov.au" target="_blank">VIC</a> · <a href="https://education.nsw.gov.au/school-finder" target="_blank">NSW</a></p></div>';
CMP.lifestyle='<div class="card"><h2>🌏 Lifestyle</h2><div class="table-wrap"><table><tr><th></th><th style="color:var(--accent)">Melbourne</th><th style="color:var(--orange)">Sydney</th></tr><tr><td style="font-weight:600">Climate</td><td>Four seasons. Cold winters 5–14°C. "Four seasons in one day"</td><td>Milder winters 8–17°C. More sunshine, warmer</td></tr><tr><td style="font-weight:600">Beaches</td><td>Port Phillip Bay — calm, family-friendly</td><td>World-class — Bondi, Manly, Coogee</td></tr><tr><td style="font-weight:600">Culture & Food</td><td>Coffee capital. Laneways, street art, live music. #1 for culture</td><td>Harbour, Opera House, cosmopolitan dining</td></tr><tr><td style="font-weight:600">Sport</td><td>AFL heartland. MCG, F1, Australian Open</td><td>NRL/rugby. Cricket, surfing culture</td></tr><tr><td style="font-weight:600">Kids activities</td><td>AFL Auskick, cricket, swimming, tennis</td><td>Surfing, rugby, swimming, cricket</td></tr><tr><td style="font-weight:600">Commute</td><td>Trains + trams. Free tram zone CBD. 30–45 min from east</td><td>Trains + buses + ferries. 45–60+ min from family suburbs</td></tr><tr><td style="font-weight:600">Sunny days/yr</td><td>~185</td><td>~230</td></tr><tr><td style="font-weight:600">Liveability</td><td>Top 5 globally (EIU)</td><td>Top 10 globally</td></tr><tr><td style="font-weight:600">Airport</td><td>No rail link. 25 min to city</td><td>Train link. More direct Asia/Europe flights</td></tr></table></div><p class="ts mt2">💡 Coming from the UK, both are a massive upgrade. Sydney = beaches + sunshine. Melbourne = culture + food + sport.</p></div><div class="card"><h2>🏥 Safety</h2><div class="table-wrap"><table><tr><th></th><th style="color:var(--accent)">Melbourne</th><th style="color:var(--orange)">Sydney</th></tr><tr><td>Safest family suburb</td><td>Warranwood (1,141/100k)</td><td>Beecroft (1,098/100k)</td></tr><tr><td>Target area safety</td><td>Glen Waverley: 5,232<br>Doncaster East: 2,422</td><td>Epping: 2,345<br>Carlingford: 2,828</td></tr></table></div><p class="ts mt2">Both very safe in family suburbs. Comparable.</p></div>';
CMP.verdict='<div class="card" style="border-left:4px solid var(--accent)"><h2 style="color:var(--accent)">✅ Choose Melbourne If...</h2><ul class="ts" style="margin:8px 0 0 20px;line-height:2.2"><li><strong>Budget matters</strong> — $13k–$19k/yr cheaper in rent</li><li><strong>Best free schools</strong> — Glen Waverley SC 91.40, Balwyn HS 91.50</li><li><strong>More savings</strong> — ~$3,600/mo surplus vs ~$2,300</li><li><strong>Culture & food</strong> — coffee, laneways, restaurants</li><li><strong>AFL & sport</strong> — MCG, F1, Australian Open</li><li><strong>Research done</strong> — schools, suburbs, quotes all lined up</li></ul></div><div class="card" style="border-left:4px solid var(--orange)"><h2 style="color:var(--orange)">✅ Choose Sydney If...</h2><ul class="ts" style="margin:8px 0 0 20px;line-height:2.2"><li><strong>Beaches</strong> — Bondi, Manly, Coogee are world-class</li><li><strong>Better weather</strong> — warmer winters, more sunshine</li><li><strong>Selective schools</strong> — larger network from Year 7</li><li><strong>International flights</strong> — more direct connections</li><li><strong>Harbour lifestyle</strong> — iconic, cosmopolitan</li></ul></div><div class="card"><h2>📊 Bottom Line</h2><div class="table-wrap"><table><tr><th></th><th style="color:var(--accent)">Melbourne</th><th style="color:var(--orange)">Sydney</th></tr><tr style="font-weight:600"><td>Monthly surplus</td><td style="color:var(--green)">~$3,600</td><td style="color:var(--orange)">~$2,300</td></tr><tr style="font-weight:600"><td>Annual surplus</td><td style="color:var(--green)">~$43,200</td><td style="color:var(--orange)">~$27,600</td></tr><tr style="font-weight:600"><td>Extra cost of Sydney/yr</td><td colspan="2" style="text-align:center;color:var(--red)">~$15,600</td></tr><tr style="font-weight:600"><td>Best zoned school</td><td style="color:var(--green)">91.50</td><td>88.93</td></tr><tr style="font-weight:600"><td>Family rent/wk</td><td style="color:var(--green)">$700–$875</td><td>$900–$1,200</td></tr></table></div><p class="ts mt2">Melbourne is financially stronger by ~$15k/yr. Sydney offers beaches + weather at a premium. Both excellent for families.</p></div>';

